targets.expr:
((
  100 * (1 - (sum by(nodename) (
  node_memory_MemAvailable_bytes{job="node-exporter"}
    * on(instance) group_left(nodename) max by(instance,nodename) (node_uname_info{job="node-exporter"})
) / clamp_min(sum by(nodename) (
  node_memory_MemTotal_bytes{job="node-exporter"}
    * on(instance) group_left(nodename) max by(instance,nodename) (node_uname_info{job="node-exporter"})
), 1)))
)
or on(nodename)
(
  -1 * (max by(nodename) (label_replace(kube_node_info, "nodename", "$1", "node", "(.*)")) unless on(nodename) (max by(nodename) (label_replace(up{job="node-exporter"} == 1, "nodename", "$1", "node", "(.*)")) and on(nodename) max by(nodename) (label_replace(kube_node_status_condition{condition="Ready",status="true"} == 1, "nodename", "$1", "node", "(.*)"))))
))
  * on(nodename) group_left() max by(nodename) (label_replace(kube_node_role{role=~"control-plane|master"}, "nodename", "$1", "node", "(.*)"))

((
  100 * (1 - (sum by(nodename) (
  node_memory_MemAvailable_bytes{job="node-exporter"}
    * on(instance) group_left(nodename) max by(instance,nodename) (node_uname_info{job="node-exporter"})
) / clamp_min(sum by(nodename) (
  node_memory_MemTotal_bytes{job="node-exporter"}
    * on(instance) group_left(nodename) max by(instance,nodename) (node_uname_info{job="node-exporter"})
), 1)))
)
or on(nodename)
(
  -1 * (max by(nodename) (label_replace(kube_node_info, "nodename", "$1", "node", "(.*)")) unless on(nodename) (max by(nodename) (label_replace(up{job="node-exporter"} == 1, "nodename", "$1", "node", "(.*)")) and on(nodename) max by(nodename) (label_replace(kube_node_status_condition{condition="Ready",status="true"} == 1, "nodename", "$1", "node", "(.*)"))))
))
  unless on(nodename) max by(nodename) (label_replace(kube_node_role{role=~"control-plane|master"}, "nodename", "$1", "node", "(.*)"))

100 * (
(sum(
  kube_deployment_status_replicas_available{namespace=~"${infra_namespaces:raw}"}
    * on(namespace,deployment) group_left(label_app_kubernetes_io_part_of)
      kube_deployment_labels{namespace=~"${infra_namespaces:raw}",label_app_kubernetes_io_part_of=~"${component:regex}"}
) or vector(0))
+
(sum(
  kube_statefulset_status_replicas_ready{namespace=~"${infra_namespaces:raw}"}
    * on(namespace,statefulset) group_left(label_app_kubernetes_io_part_of)
      kube_statefulset_labels{namespace=~"${infra_namespaces:raw}",label_app_kubernetes_io_part_of=~"${component:regex}"}
) or vector(0))
+
(sum(
  kube_daemonset_status_number_available{namespace=~"${infra_namespaces:raw}"}
    * on(namespace,daemonset) group_left(label_app_kubernetes_io_part_of)
      kube_daemonset_labels{namespace=~"${infra_namespaces:raw}",label_app_kubernetes_io_part_of=~"${component:regex}"}
) or vector(0))
)
/
clamp_min((
(sum(
  kube_deployment_spec_replicas{namespace=~"${infra_namespaces:raw}"}
    * on(namespace,deployment) group_left(label_app_kubernetes_io_part_of)
      kube_deployment_labels{namespace=~"${infra_namespaces:raw}",label_app_kubernetes_io_part_of=~"${component:regex}"}
) or vector(0))
+
(sum(
  kube_statefulset_replicas{namespace=~"${infra_namespaces:raw}"}
    * on(namespace,statefulset) group_left(label_app_kubernetes_io_part_of)
      kube_statefulset_labels{namespace=~"${infra_namespaces:raw}",label_app_kubernetes_io_part_of=~"${component:regex}"}
) or vector(0))
+
(sum(
  kube_daemonset_status_desired_number_scheduled{namespace=~"${infra_namespaces:raw}"}
    * on(namespace,daemonset) group_left(label_app_kubernetes_io_part_of)
      kube_daemonset_labels{namespace=~"${infra_namespaces:raw}",label_app_kubernetes_io_part_of=~"${component:regex}"}
) or vector(0))
), 1)
